from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["god-mode-self-diagnosis-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>God Mode Self Diagnosis</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e;--warn:#f59e0b;--bad:#ef4444}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px}button,input,textarea,select{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}textarea{width:100%;min-height:80px}.item{border-left:4px solid var(--warn);padding:9px 10px;background:#081226;border-radius:14px}.blocker{border-left-color:var(--bad)}.low{border-left-color:var(--ok)}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>God Mode Self Diagnosis</h1><p class="muted">Diagnóstico do próprio God Mode: o que falta para ficar real, instalável e capaz de autoevoluir por PRs gated.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/first-pc-install-ready-pack'" class="dark">Install Pack</button><button onclick="run()">Diagnosticar agora</button><button onclick="dashboard()">Dashboard</button><button onclick="queue()">Fila self-fix</button></div></section><section class="panel"><h2>Lacunas prioritárias</h2><div id="items" class="grid"></div></section><section class="panel"><h2>Gerir item</h2><input id="itemId" style="width:100%" placeholder="self-fix-..."/><div class="grid"><select id="status"><option>needs_review</option><option>approved_for_planning</option><option>planned</option><option>blocked</option><option>done</option><option>dismissed</option><option>open</option></select><button onclick="updateItem()">Atualizar estado</button><button onclick="brief()">Criar PR brief</button></div><textarea id="note">Atualização feita no cockpit.</textarea></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s??'').replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){const items=x?.self_fix_queue_items||x?.self_fix_queue||x?.latest_diagnostic_run?.gaps||x?.dashboard?.self_fix_queue||[];qs('#items').innerHTML=items.slice(0,24).map(it=>{const sev=it.severity||'low';const cls=sev==='blocker'?'blocker':sev==='low'?'low':'';const id=it.self_fix_queue_item_id||it.gap_id||'';return `<div class="item ${cls}" onclick="qs('#itemId').value='${esc(id)}'"><b>${esc(sev)}</b><br>${esc(it.title||it.gap_id)}<br><span class="muted">${esc(it.reason||it.recommended_next_step)}</span></div>`}).join('')}async function run(){show(await api('/api/god-mode-self-diagnosis/run',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({focus:'install_first_then_self_evolve'})}))}async function dashboard(){show(await api('/api/god-mode-self-diagnosis/dashboard'))}async function queue(){show(await api('/api/god-mode-self-diagnosis/queue?limit=150'))}async function updateItem(){show(await api('/api/god-mode-self-diagnosis/update-queue-item',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({self_fix_queue_item_id:qs('#itemId').value,status:qs('#status').value,note:qs('#note').value})}))}async function brief(){show(await api('/api/god-mode-self-diagnosis/create-pr-planning-brief',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({self_fix_queue_item_id:qs('#itemId').value})}))}dashboard()</script></body></html>
"""


@router.get('/app/god-mode-self-diagnosis', response_class=HTMLResponse)
async def god_mode_self_diagnosis_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/self-fix-mission-control', response_class=HTMLResponse)
async def self_fix_mission_control_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
